// Compact JS wrapper example
class SimpleCB {
  constructor(threshold = 5, timeout = 10000) {
    this.threshold = threshold; this.timeout = timeout; this.failures = 0; this.state = 'CLOSED'; this.nextTry = 0
  }
  async run(fn) {
    if (this.state === 'OPEN' && Date.now() < this.nextTry) throw new Error('open')
    try {
      const r = await fn(); this.failures = 0; this.state = 'CLOSED'; return r
    } catch (e) {
      this.failures++
      if (this.failures >= this.threshold) { this.state = 'OPEN'; this.nextTry = Date.now() + this.timeout }
      throw e
    }
  }
}
